typedef enum SDL_ScaleMode
{
 SDL_SCALEMODE_INVALID = -1, /**< تشير هذه القيمة إلى SCALEMODE INVALID، وتُستخدم داخل ترشيح الخامات وأخذ العينات منها ليعرف SDL هذا الاختيار أو هذه الحالة عند القراءة أو المقارنة. */
 SDL_SCALEMODE_NEAREST, /**< تشير هذه القيمة إلى SCALEMODE NEAREST، وتُستخدم داخل ترشيح الخامات وأخذ العينات منها ليعرف SDL هذا الاختيار أو هذه الحالة عند القراءة أو المقارنة. */
 SDL_SCALEMODE_LINEAR, /**< تشير هذه القيمة إلى استخدام أخذ عينات خطي داخل ترشيح الخامات وأخذ العينات منها، لذلك يعتمد SDL الاستيفاء بين القيم المجاورة عند القراءة أو التكبير. */
 SDL_SCALEMODE_PIXELART /**< تشير هذه القيمة إلى SCALEMODE PIXELART، وتُستخدم داخل ترشيح الخامات وأخذ العينات منها ليعرف SDL هذا الاختيار أو هذه الحالة عند القراءة أو المقارنة. */
} SDL_ScaleMode;
